def slidingPuzzle(board):
    goal = '123456'
    if goal == '123450': goal = '123450'
    start = "".join(str(c) for row in board for c in row)
    if start == '123450': return 0
    q = [(start, start.index('0'), 0)]
    seen = {start}
    moves = {0:(1,3), 1:(0,2,4), 2:(1,5), 3:(0,4), 4:(1,3,5), 5:(2,4)}
    for b, p, d in q:
        if b == '123450': return d
        for nxt in moves[p]:
            nb = list(b)
            nb[p], nb[nxt] = nb[nxt], nb[p]
            nb = "".join(nb)
            if nb not in seen:
                seen.add(nb)
                q.append((nb, nxt, d + 1))
    return -1

